action.storedProcedure:
CREATE OR REPLACE  PROCEDURE "STP_CRIA_SUBPROJETO_NEUON" (
       P_CODUSU NUMBER,        -- Código do usuário logado
       P_IDSESSAO VARCHAR2,    -- Identificador da execução. Serve para buscar informações dos parâmetros/campos da execução.
       P_QTDLINHAS NUMBER,     -- Informa a quantidade de registros selecionados no momento da execução.
       P_MENSAGEM OUT VARCHAR2 -- Caso seja passada uma mensagem aqui, ela será exibida como uma informação ao usuário.
) AS
       PARAM_DESCR_SUBPROJ VARCHAR2(4000);
       FIELD_NUATV NUMBER;
       V_NEGOCIO   VARCHAR2(4000);
       P_COUNT  NUMBER;
       V_SEQ    NUMBER;
BEGIN

       -- Os valores informados pelo formulário de parâmetros, podem ser obtidos com as funções:
       --     ACT_INT_PARAM
       --     ACT_DEC_PARAM
       --     ACT_TXT_PARAM
       --     ACT_DTA_PARAM
       -- Estas funções recebem 2 argumentos:
       --     ID DA SESSÃO - Identificador da execução (Obtido através de P_IDSESSAO))
       --     NOME DO PARAMETRO - Determina qual parametro deve se deseja obter.

       PARAM_DESCR_SUBPROJ := ACT_TXT_PARAM(P_IDSESSAO, 'DESCR_SUBPROJ');

       FOR I IN 1..P_QTDLINHAS -- Este loop permite obter o valor de campos dos registros envolvidos na execução.
       LOOP                    -- A variável "I" representa o registro corrente.
           -- Para obter o valor dos campos utilize uma das seguintes funções:
           --     ACT_INT_FIELD (Retorna o valor de um campo tipo NUMÉRICO INTEIRO))
           --     ACT_DEC_FIELD (Retorna o valor de um campo tipo NUMÉRICO DECIMAL))
           --     ACT_TXT_FIELD (Retorna o valor de um campo tipo TEXTO),
           --     ACT_DTA_FIELD (Retorna o valor de um campo tipo DATA)
           -- Estas funções recebem 3 argumentos:
           --     ID DA SESSÃO - Identificador da execução (Obtido através do parâmetro P_IDSESSAO))
           --     NÚMERO DA LINHA - Relativo a qual linha selecionada.
           --     NOME DO CAMPO - Determina qual campo deve ser obtido.
           --FIELD_NUATV := ACT_INT_FIELD(P_IDSESSAO, I, 'NUATV');
           --V_NEGOCIO := ACT_TXT_PARAM(P_IDSESSAO, 'NEGOCIO');

        --EVITA DUPLICIDADE
           SELECT COUNT(*) INTO P_COUNT FROM AD_SUBPROJETOS WHERE NEGOCIO = 'B' AND UPPER(DESCRSUBPROJ) = UPPER(PARAM_DESCR_SUBPROJ);
           IF P_COUNT > 0 THEN
                P_MENSAGEM := 'ERRO. Subprojeto já cadastrado!';
                RETURN;
           END IF;

        --INSERE SUBPROJETO BRAION
           SELECT NVL(MAX(CODSUBPROJ),0) + 1 INTO V_SEQ FROM AD_SUBPROJETOS;
           INSERT INTO AD_SUBPROJETOS (CODSUBPROJ, NEGOCIO, DESCRSUBPROJ)
           VALUES (V_SEQ, 'B', UPPER(PARAM_DESCR_SUBPROJ));

           P_MENSAGEM := 'Adicionado com Sucesso!';


       END LOOP;




-- <ESCREVA SEU CÓDIGO DE FINALIZAÇÃO AQUI> --



END;

CREATE OR REPLACE  PROCEDURE "STP_CRIA_SOLICITANTE_NEUON" (
       P_CODUSU NUMBER,        -- Código do usuário logado
       P_IDSESSAO VARCHAR2,    -- Identificador da execução. Serve para buscar informações dos parâmetros/campos da execução.
       P_QTDLINHAS NUMBER,     -- Informa a quantidade de registros selecionados no momento da execução.
       P_MENSAGEM OUT VARCHAR2 -- Caso seja passada uma mensagem aqui, ela será exibida como uma informação ao usuário.
) AS
       PARAM_DESCR_SOL VARCHAR2(4000);
       PARAM_CODPARC    NUMBER;
       PARAM_TELEFONE VARCHAR2(4000);
       PARAM_EMAIL VARCHAR2(4000);
       FIELD_NUATV NUMBER;
       V_CODPARC   VARCHAR2(4000);
       P_COUNT  NUMBER;
       V_SEQ    NUMBER;
BEGIN

       -- Os valores informados pelo formulário de parâmetros, podem ser obtidos com as funções:
       --     ACT_INT_PARAM
       --     ACT_DEC_PARAM
       --     ACT_TXT_PARAM
       --     ACT_DTA_PARAM
       -- Estas funções recebem 2 argumentos:
       --     ID DA SESSÃO - Identificador da execução (Obtido através de P_IDSESSAO))
       --     NOME DO PARAMETRO - Determina qual parametro deve se deseja obter.

       PARAM_DESCR_SOL := ACT_TXT_PARAM(P_IDSESSAO, 'DESCR_SOL');
       PARAM_CODPARC := ACT_INT_PARAM(P_IDSESSAO, 'CODPARC');
       PARAM_TELEFONE := ACT_TXT_PARAM(P_IDSESSAO, 'TELEFONE');
       PARAM_EMAIL := ACT_TXT_PARAM(P_IDSESSAO, 'EMAIL');

       FOR I IN 1..P_QTDLINHAS -- Este loop permite obter o valor de campos dos registros envolvidos na execução.
       LOOP                    -- A variável "I" representa o registro corrente.
           -- Para obter o valor dos campos utilize uma das seguintes funções:
           --     ACT_INT_FIELD (Retorna o valor de um campo tipo NUMÉRICO INTEIRO))
           --     ACT_DEC_FIELD (Retorna o valor de um campo tipo NUMÉRICO DECIMAL))
           --     ACT_TXT_FIELD (Retorna o valor de um campo tipo TEXTO),
           --     ACT_DTA_FIELD (Retorna o valor de um campo tipo DATA)
           -- Estas funções recebem 3 argumentos:
           --     ID DA SESSÃO - Identificador da execução (Obtido através do parâmetro P_IDSESSAO))
           --     NÚMERO DA LINHA - Relativo a qual linha selecionada.
           --     NOME DO CAMPO - Determina qual campo deve ser obtido.
           FIELD_NUATV := ACT_INT_FIELD(P_IDSESSAO, I, 'NUATV');
           V_CODPARC := ACT_TXT_PARAM(P_IDSESSAO, 'CODPARC');

        --EVITA DUPLICIDADE
           SELECT COUNT(*) INTO P_COUNT FROM AD_SOLCLI WHERE CODPARC = NVL(PARAM_CODPARC,V_CODPARC) AND UPPER(NOMESOL) = UPPER(PARAM_DESCR_SOL);
           IF P_COUNT > 0 THEN
                P_MENSAGEM := 'ERRO. Solicitante já cadastrado!';
                RETURN;
           END IF;

           IF PARAM_CODPARC IS NULL AND V_CODPARC IS NULL THEN
                P_MENSAGEM := 'ERRO. Informe um Parceiro!';
                RETURN;
           END IF;


        --INSERE SUBPROJETO BRAION
           SELECT NVL(MAX(SOLICITANTE),0) + 1 INTO V_SEQ FROM AD_SOLCLI;
           INSERT INTO AD_SOLCLI (SOLICITANTE, CODPARC, NOMESOL, TELEFONE, EMAIL)
           VALUES (V_SEQ, NVL(PARAM_CODPARC,V_CODPARC), UPPER(PARAM_DESCR_SOL), PARAM_TELEFONE, PARAM_EMAIL);

           P_MENSAGEM := 'Adicionado com Sucesso!';

       END LOOP;




-- <ESCREVA SEU CÓDIGO DE FINALIZAÇÃO AQUI> --



END;

relation.expression:
@form-filter[this.AD_NEGOCIO = (select negocio from ad_negociacoes where neg_id = form.NEG_ID)
AND
this.AD_CODPARC = (select codparc from ad_negociacoes where neg_id = form.NEG_ID)]
